package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() throws IOException {
        out = new StringBuilder();
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintRecord_withNonNullValues() throws Exception {
        StringBuilder appendable = new StringBuilder();
        CSVPrinter csvPrinter = new CSVPrinter(appendable, format);

        // Create a custom Appendable that appends raw values
        class RawAppendable implements Appendable {
            private final StringBuilder sb;

            RawAppendable(StringBuilder sb) {
                this.sb = sb;
            }

            @Override
            public Appendable append(CharSequence csq) {
                sb.append(csq);
                return this;
            }

            @Override
            public Appendable append(CharSequence csq, int start, int end) {
                sb.append(csq, start, end);
                return this;
            }

            @Override
            public Appendable append(char c) {
                sb.append(c);
                return this;
            }
        }

        RawAppendable rawAppendable = new RawAppendable(appendable);

        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        outField.set(csvPrinter, rawAppendable);

        csvPrinter.printRecord("a", 123, true);

        assertEquals("a123true\n", appendable.toString());
    }

